queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?activity_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasActivities ?child ; p:hasAdventure_Tour_Operators ?parent . } GROUP BY ?child }
  ?child p:activity_name ?activity_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Adventure_Tour_Operators } }
  FILTER(?nf = ?total)
}

